final:
module load_reg(
   input                clk ,
   input                rst_n,
   input                load,
   input  [31:0]        data_in,

   output reg [31:0]    obf_Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) obf_Q <= 'd0;
        else if(load) obf_Q <= data_in;
    end
endmodule
